#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int P1, P2, K;
        scanf("%d %d %d", &P1, &P2, &K);
        int total = P1 + P2;
        if ((total / K) % 2 == 0) {
            printf("CHEF\n");
        } else {
            printf("COOK\n");
        }
    }
    return 0;
}

