const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [P1, P2, K] = readline().split(' ').map(Number);
    const total = P1 + P2;
    if (Math.floor(total / K) % 2 === 0) {
        console.log('CHEF');
    } else {
        console.log('COOK');
    }
}
